UNPATCHED vulnerable pseudocode (CsvCamSetSecurityInfo / sub_1C00BCAAC):

    int32_t len = *(arg1 + 0xe8);            // cached in eax at entry
    if (len != 0)
    {
        Encryption* rdx_1 = EncryptionManager;  // NO LOCK - unprotected global read
        r14 = 1;
        if (rdx_1) {
            int32_t size = *(rdx_1 + 0x20);     // deref of unprotected ptr (stored size)
            if (len == size &&
                memcmp(arg1 + 0xec, *(rdx_1 + 0x18), size) == 0)  // deref +0x18 (stored buf)
                r14 = 0;                        // input matches existing manager
        }
        // allocate replacement, then:
        //   KeEnterCriticalRegion();
        //   ExAcquireResourceExclusiveLite(*SigningLock, 1);
        //   if (EncryptionManager) ??_GEncryption(EncryptionManager);  // frees old (ExFreePoolWithTag)
        //   EncryptionManager = new_object;                            // replace global
        //   ExReleaseResourceLite(*SigningLock);
        //   KeLeaveCriticalRegion();
    }

PATCHED fixed pseudocode:

    if (*(arg1 + 0xe8) > 0)
    {
        r14 = 1;
        RWLock::AcquireShared();                 // SigningLock shared acquire (sub_1C0018818)
        Encryption* rdx_1 = EncryptionManager;   // read under lock
        if (rdx_1) {
            int32_t size = *(rdx_1 + 0x20);      // safe deref under shared lock
            if (*(arg1 + 0xe8) == size &&        // re-read arg1+0xe8 from memory
                memcmp(arg1 + 0xec, *(rdx_1 + 0x18), size) == 0)
                r14 = 0;
        }
        RWLock::ReleaseShared();                 // SigningLock shared release (sub_1C0018850)
        // ... allocate replacement / exclusive swap as before ...
    }
